/** ============================================================
 * QAcademy Payments WebApp (v0.2)
 * - Stores payment lifecycle in Payments sheet tab: "payments"
 * - Reads product price dynamically from PortalAuthv2 products tab
 * - Initializes Paystack transaction
 * - Verifies Paystack transaction (success page OR webhook)
 * - Activates access in PortalAuthv2 via payments_activate (recommended)
 *
 * NEW in v0.2:
 * - pay_init_upgrade: existing logged-in users can buy another product without creating a new user
 * - optional PAYMENTS_DB_ID (payments sheet can live in a separate spreadsheet)
 * - product_name snapshot stored into payments row (if column exists)
 * ============================================================ */

const BUILD = 'payments-v0.2-2026-01-03-upgrade-init';

/** ========== CONFIG (edit these) ========== */

// PortalAuthv2 WebApp URL (your existing Auth webapp)
const PORTAL_AUTH_URL = 'https://script.google.com/macros/s/AKfycbxaChsaqn6Or1G-SHqsXla1DdgYdWXzXLfs9GVs_7xrxDeYwjT0OhvWlYUsJtpMU8so/exec';

// PortalAuthv2 *Spreadsheet ID* (so we can read products pricing dynamically)
const PORTAL_DB_ID = '1Aq0IaPOjC1Vo4bQb8aP0S0bO5EaeUx_4oYUlnJ2g2vc';

// OPTIONAL: Payments DB Spreadsheet ID (recommended if you want payments in a separate DB)
// - If you leave this blank, the code will FALL BACK to PORTAL_DB_ID.
// - This keeps backward compatibility with your current deployment.
const PAYMENTS_DB_ID = '1Aq0IaPOjC1Vo4bQb8aP0S0bO5EaeUx_4oYUlnJ2g2vc'; // <-- set this to your Payments DB spreadsheet id when ready

// Tab names in Portal DB
const PORTAL_TAB_PRODUCTS = 'products';
const PORTAL_TAB_PROGRAMS = 'programs';

// Payments tab name
const TAB_PAYMENTS = 'payments';

// Paystack
const PAYSTACK_INIT_URL   = 'https://api.paystack.co/transaction/initialize';
const PAYSTACK_VERIFY_URL = 'https://api.paystack.co/transaction/verify/'; // + reference

// Script Properties keys (set these in Apps Script → Project Settings → Script properties)
const PROP_PAYSTACK_SECRET_KEY = 'PAYSTACK_SECRET_KEY';

// Shared secret used by PortalAuthv2 payments_activate
const PROP_PORTAL_PAYMENTS_SECRET = 'PORTAL_PAYMENTS_SECRET';

// Choose activation strategy:
// 1) RECOMMENDED: call PortalAuthv2 action=payments_activate using PORTAL_PAYMENTS_SECRET
// 2) fallback: call action=assign_product with an admin token (NOT recommended; tokens expire)
const ACTIVATION_MODE = 'PAYMENTS_ACTIVATE'; // 'PAYMENTS_ACTIVATE' | 'ASSIGN_PRODUCT_WITH_ADMIN_TOKEN'
const PROP_PORTAL_ADMIN_TOKEN = 'PORTAL_ADMIN_TOKEN'; // only used if ACTIVATION_MODE = ASSIGN_PRODUCT_WITH_ADMIN_TOKEN


/** ========== HTTP ENTRYPOINTS ========== */

function doGet(e){
  const a = String((e && e.parameter && e.parameter.action) || '').toLowerCase();

  if (a === 'health') return _json({ ok:true, service:'QAcademyPayments', build:BUILD, now:_iso(new Date()) });

  if (a === 'pay_status') {
    const reference = String((e.parameter.reference || '')).trim();
    if(!reference) return _json({ ok:false, error:'missing_reference' });
    return apiPayStatus({ reference });
  }

  if (a === 'meta') {
    return apiMeta();
  }

  // Convenience GET: verify payment reference (used by success page)
  if (a === 'pay_verify') {
    const reference = String((e.parameter.reference || '')).trim();
    if(!reference) return _json({ ok:false, error:'missing_reference' });
    return apiPayVerify({ reference });
  }

  return _json({ ok:false, error:'unknown_action' });
}

function doPost(e){
  try{
    const p = (e && e.parameter) || {};
    const rawBody = (e && e.postData && e.postData.contents) ? e.postData.contents : '';

    // We allow JSON parsing for admin/testing, but most clients should POST form-encoded
    let body = {};
    try { body = JSON.parse(rawBody || '{}'); } catch(_){ body = {}; }

    const action = String(p.action || body.action || '').trim().toLowerCase();

    // ✅ If no action, try to auto-detect Paystack webhook
    if(!action){
      const sig = _getHeaderCI_(e, 'x-paystack-signature');
      const looksLikePaystack = rawBody && rawBody.indexOf('"event"') !== -1 && rawBody.indexOf('"data"') !== -1;

      if(sig || looksLikePaystack){
        return apiPayWebhook(e);
      }
      return _json({ ok:false, error:'missing_action' });
    }

    // Public: initialize payment (new-user paid onboarding)
    if(action === 'pay_init') return apiPayInit(_merge(p, body));

    // NEW: initialize payment for EXISTING user (upgrade/extend) - token required
    if(action === 'pay_init_upgrade') return apiPayInitUpgrade(_merge(p, body));

   // Public: initialize payment (PAY-FIRST quick flow; no user creation)
    if(action === 'pay_init_quick') return apiPayInitQuick(_merge(p, body));

    // Called by your "Payment success" page OR by admin tools
    if(action === 'pay_verify'){
      return apiPayVerify({ reference: String(p.reference || body.reference || '').trim() });
    }

    // PAY-FIRST: post-payment setup (create account + activate)
     if(action === 'setup_complete') return apiSetupComplete(_merge(p, body));

    // Paystack webhook (still supported if you set URL ?action=pay_webhook)
    if(action === 'pay_webhook') return apiPayWebhook(e);

    return _json({ ok:false, error:'unknown_action' });

  } catch(err){
    return _json({ ok:false, error:String(err && (err.stack || err.message) || err) });
  }
}



/** ============================================================
 * API: pay_init (NEW USER FLOW)
 * - Inputs: user registration fields + product_id
 * - Creates user in PortalAuthv2 via action=self_register_paid
 * - Reads product price from Portal products tab (price_minor + currency)
 * - Calls Paystack initialize
 * - Writes payments row (INIT)
 * - Returns authorization_url + reference
 * ============================================================ */
function apiPayInit(args){
  const product_id   = String(args.product_id || '').trim().toUpperCase();
  const forename     = String(args.forename || '').trim();
  const surname      = String(args.surname || '').trim();
  const email        = String(args.email || '').trim().toLowerCase();
  const password     = String(args.password || '');
  const phone_number = String(args.phone_number || '').trim();
  const program_id   = String(args.program_id || '').trim();
  const cohort       = String(args.cohort || '').trim();
  const username     = String(args.username || args.reg_username || '').trim().toLowerCase();
  const avatar_url   = String(args.avatar_url || '').trim();
  const callback_url = String(args.callback_url || '').trim();

  // Optional client info
  const ua = String(args.ua || '');
  const ip = String(args.ip || '');

  if(!product_id || !forename || !surname || !email || !password){
    return _json({ ok:false, error:'missing_fields' });
  }

  // 1) Create the user in PortalAuthv2 (paid onboarding route, no trial assignment)
  const reg = _portalPost_({
    action: 'self_register_paid',
    forename, surname, email, password,
    phone_number, program_id, cohort, avatar_url,
    username,
    ua, ip,
    product_id // helpful for audit/logs
  });

  if(!reg.ok){
    return _json({ ok:false, error:'portal_register_failed', portal_error: reg.error || '' });
  }

  const user_id = reg.user_id || '';
  const username_created = reg.username || '';

  // 2) Read dynamic price from PortalAuthv2 products tab
  const prod = _getProductPricingFromPortal_(product_id);
  if(!prod.ok){
    return _json({ ok:false, error: prod.error || 'product_lookup_failed' });
  }

  const amount_minor_expected = prod.price_minor;
  const currency              = prod.currency || 'GHS';
  const product_name          = prod.name || product_id;

  // 3) Call Paystack initialize
  const initRes = _paystackInitialize_({
    email,
    amount_minor: amount_minor_expected,
    currency,
    metadata: {
      product_id,
      product_name,
      user_id,
      program_id,
      cohort,
      phone_number,
      flow: 'new_user'
    },
    callback_url
  });

  if(!initRes.ok){
    // user is created but payment init failed; acceptable for MVP
    return _json({ ok:false, error:'paystack_init_failed', detail: initRes.error || '' });
  }

  const reference = initRes.reference;
  const authorization_url = initRes.authorization_url;

  // 4) Write payments row INIT (store product_name snapshot if column exists)
  _paymentsUpsertByReference_(reference, {
    reference,
    status: 'INIT',
    email,
    user_id,
    product_id,
    product_name,                 // <-- snapshot (requires a 'product_name' column to persist)
    amount_minor_expected,
    currency,
    amount_minor_paid: '',
    paid_utc: '',
    activated_utc: '',
    portal_subscription_id: '',
    failure_note: '',
    raw: JSON.stringify({ init: initRes.raw || {} })
  });

  return _json({
    ok:true,
    reference,
    authorization_url,
    product_id,
    product_name,
    amount_minor_expected,
    currency,
    user_id,
    username: username_created,
    email,
    phone_number
  });
}

/** ============================================================
 * API: pay_init_quick (PAY-FIRST FLOW)
 * - Inputs: email + product_id (+ optional phone/program) + callback_url
 * - DOES NOT create a user
 * - Reads product price dynamically from Portal products tab
 * - Calls Paystack initialize
 * - Writes payments row (INIT) with user_id blank
 * - Returns authorization_url + reference
 * ============================================================ */
function apiPayInitQuick(args){
  var product_id   = String(args.product_id || '').trim().toUpperCase();
  var email        = String(args.email || '').trim().toLowerCase();
  var phone_number = String(args.phone_number || '').trim();
  var program_id   = String(args.program_id || '').trim().toUpperCase();
  var callback_url = String(args.callback_url || '').trim();

  // Optional client info
  var ua = String(args.ua || '');
  var ip = String(args.ip || '');

  if(!product_id) return _json({ ok:false, error:'missing_product_id' });
  if(!email)      return _json({ ok:false, error:'missing_email' });
  if(!callback_url) return _json({ ok:false, error:'missing_callback_url' });

  // 1) Read dynamic price
  var prod = _getProductPricingFromPortal_(product_id);
  if(!prod.ok){
    return _json({ ok:false, error: prod.error || 'product_lookup_failed' });
  }

  var amount_minor_expected = prod.price_minor;
  var currency              = prod.currency || 'GHS';
  var product_name          = prod.name || product_id;

  // 2) Optional setup token (for later post-payment setup; safe even if you don't use yet)
  var setup_token = _randToken_();

  // Append setup token onto callback_url so confirmation page can read it later (optional)
  var cb = _addQueryParam_(callback_url, 'setup', setup_token);

  // 3) Paystack initialize
  var initRes = _paystackInitialize_({
    email: email,
    amount_minor: amount_minor_expected,
    currency: currency,
    metadata: {
      product_id: product_id,
      product_name: product_name,
      program_id: program_id,
      phone_number: phone_number,
      flow: 'quick',
      ua: ua || undefined,
      ip: ip || undefined
    },
    callback_url: cb
  });

  if(!initRes.ok){
    return _json({ ok:false, error:'paystack_init_failed', detail: initRes.error || '', raw: initRes.raw || {} });
  }

  var reference = initRes.reference;
  var authorization_url = initRes.authorization_url;

  // 4) Write payments row INIT (user_id intentionally blank)
  _paymentsUpsertByReference_(reference, {
    reference: reference,
    status: 'INIT',
    email: email,
    user_id: '', // <-- pay-first: no user created yet
    product_id: product_id,
    product_name: product_name,
    program_id: program_id,
    phone_number: phone_number,
    amount_minor_expected: amount_minor_expected,
    currency: currency,
    amount_minor_paid: '',
    paid_utc: '',
    activated_utc: '',
    portal_subscription_id: '',
    failure_note: '',
    setup_token: setup_token,                 // persists only if column exists
    setup_created_utc: _iso(new Date()),      // persists only if column exists
    raw: JSON.stringify({ init: initRes.raw || {}, flow:'quick', program_id: program_id, phone_number: phone_number })
  });

  return _json({
    ok:true,
    reference: reference,
    authorization_url: authorization_url,
    product_id: product_id,
    product_name: product_name,
    amount_minor_expected: amount_minor_expected,
    currency: currency,
    email: email,
    phone_number: phone_number,
    program_id: program_id
  });
}


/** ============================================================
 * API: pay_init_upgrade (EXISTING USER FLOW)  ✅ NEW
 * - Inputs: token + product_id (+ optional callback_url)
 * - Verifies token with PortalAuthv2 action=verify (GET)
 * - Reads product price dynamically from Portal products tab
 * - Calls Paystack initialize using verified email
 * - Writes payments row (INIT)
 * - Returns authorization_url + reference
 *
 * This avoids creating duplicate users during upgrades/renewals.
 * ============================================================ */
function apiPayInitUpgrade(args){
  const token        = String(args.token || '').trim();
  const product_id   = String(args.product_id || '').trim().toUpperCase();
  const callback_url = String(args.callback_url || '').trim();

  // Optional (useful for metadata)
  const ua = String(args.ua || '');
  const ip = String(args.ip || '');

  if(!token) return _json({ ok:false, error:'missing_token' });
  if(!product_id) return _json({ ok:false, error:'missing_product_id' });

  // 1) Verify token with PortalAuthv2
  const me = _portalVerifyToken_(token);
  if(!me.ok) return _json({ ok:false, error:'token_invalid' });

  // Be defensive: verify payload shape can evolve
  const user_id = String(me.user_id || (me.user && me.user.user_id) || '').trim();
  const email   = String(me.email   || (me.user && me.user.email)   || '').trim().toLowerCase();
  const program_id = String(me.program_id || (me.user && me.user.program_id) || '').trim();
  const cohort     = String(me.cohort     || (me.user && me.user.cohort)     || '').trim();
  const phone_number = String(me.phone_number || (me.user && me.user.phone_number) || '').trim();

  if(!user_id || !email) return _json({ ok:false, error:'verify_missing_user_fields' });

  // 2) Read dynamic price from PortalAuthv2 products tab
  const prod = _getProductPricingFromPortal_(product_id);
  if(!prod.ok){
    return _json({ ok:false, error: prod.error || 'product_lookup_failed' });
  }

  const amount_minor_expected = prod.price_minor;
  const currency              = prod.currency || 'GHS';
  const product_name          = prod.name || product_id;

  // 3) Call Paystack initialize
  const initRes = _paystackInitialize_({
    email,
    amount_minor: amount_minor_expected,
    currency,
    metadata: {
      product_id,
      product_name,
      user_id,
      program_id,
      cohort,
      phone_number,
      flow: 'upgrade',
      ua: ua || undefined,
      ip: ip || undefined
    },
    callback_url
  });

  if(!initRes.ok){
    return _json({ ok:false, error:'paystack_init_failed', detail: initRes.error || '' });
  }

  const reference = initRes.reference;
  const authorization_url = initRes.authorization_url;

  // 4) Write payments row INIT (audit trail)
  _paymentsUpsertByReference_(reference, {
    reference,
    status: 'INIT',
    email,
    user_id,
    product_id,
    product_name,                 // snapshot (requires 'product_name' col)
    amount_minor_expected,
    currency,
    amount_minor_paid: '',
    paid_utc: '',
    activated_utc: '',
    portal_subscription_id: '',
    failure_note: '',
    raw: JSON.stringify({ init: initRes.raw || {}, kind:'upgrade' })
  });

  return _json({
    ok:true,
    reference,
    authorization_url,
    product_id,
    product_name,
    amount_minor_expected,
    currency,
    user_id,
    email
  });
}

/** ============================================================
 * API: pay_verify (UPDATED for PAY-FIRST)
 * - Verifies Paystack reference
 * - Validates amount vs amount_minor_expected stored at INIT time
 * - Activates access in PortalAuthv2 (email can resolve user)
 * - If user not found => SETUP_REQUIRED (paid is preserved)
 * ============================================================ */
function apiPayVerify({ reference }){
  if(!reference) return _json({ ok:false, error:'missing_reference' });

  // 1) Load payments row
  var pay = _paymentsGetByReference_(reference);
  if(!pay) return _json({ ok:false, error:'payment_not_found' });

  var st0 = String(pay.status || '').trim().toUpperCase();

  // Idempotency: if already activated, return quickly
  if(st0 === 'ACTIVATED'){
    return _json({ ok:true, status:'ACTIVATED', reference: reference, portal_subscription_id: pay.portal_subscription_id || '' });
  }

  // ===== FAST-PATH (no Paystack verify again) =====
  // If we already confirmed PAID or SETUP_REQUIRED, try activation again.
  // This lets the confirmation page "Retry" succeed immediately after setup_complete.
  if(st0 === 'PAID' || st0 === 'SETUP_REQUIRED'){
    var act0 = _portalActivate_(pay);
    if(act0 && act0.ok){
      _paymentsPatch_(reference, {
        status:'ACTIVATED',
        activated_utc: _iso(new Date()),
        portal_subscription_id: act0.subscription_id || '',
        user_id: act0.user_id || String(pay.user_id || '').trim(),
        raw: _mergeRaw_(pay.raw, { activation: act0.raw || {}, activation_fastpath:true })
      });
      return _json({ ok:true, reference: reference, status:'ACTIVATED', portal_subscription_id: act0.subscription_id || '' });
    }

    var ae0 = String((act0 && act0.error) || '').toLowerCase();
    if(ae0.indexOf('user_not_found') !== -1){
      // keep paid state; require setup
      // generate token if missing (only persists if col exists)
      var setupTok = String(pay.setup_token || '').trim() || _randToken_();
      _paymentsPatch_(reference, {
        status:'SETUP_REQUIRED',
        setup_token: setupTok,
        raw: _mergeRaw_(pay.raw, { activation: act0.raw || {}, setup_required:true, reason:'user_not_found_fastpath' })
      });

      return _json({
        ok:true,
        reference: reference,
        status:'SETUP_REQUIRED',
        email: String(pay.email || '').trim().toLowerCase(),
        product_id: String(pay.product_id || '').trim().toUpperCase(),
        product_name: String(pay.product_name || '').trim(),
        amount_minor_expected: pay.amount_minor_expected || '',
        currency: pay.currency || '',
        setup_token: setupTok,
        phone_number: String(pay.phone_number || '').trim(),
  program_id: String(pay.program_id || '').trim().toUpperCase(),
  cohort: String(pay.cohort || '').trim(),
  username: String(pay.username || '').trim().toLowerCase()
      });
    }

    // Any other activation failure (don’t destroy PAID state here)
    return _json({ ok:false, error:'activation_failed', detail:(act0 && act0.error) || '' });
  }

  // 2) Call Paystack verify
  var v = _paystackVerify_(reference);
  if(!v.ok){
    _paymentsPatch_(reference, {
      status:'FAILED',
      failure_note: v.error || 'verify_failed',
      raw: _mergeRaw_(pay.raw, { verify: v.raw || {} })
    });
    return _json({ ok:false, error:'paystack_verify_failed', detail: v.error || '' });
  }

  // Expected vs Paid
  var expected = parseInt(pay.amount_minor_expected, 10);
  var paid     = parseInt(v.amount_minor_paid, 10);

  if(!expected || expected <= 0){
    _paymentsPatch_(reference, {
      status:'FAILED',
      failure_note:'missing_expected_amount',
      raw: _mergeRaw_(pay.raw, { verify: v.raw || {} })
    });
    return _json({ ok:false, error:'missing_expected_amount' });
  }

  if(paid !== expected){
    _paymentsPatch_(reference, {
      status:'FAILED',
      failure_note:'amount_mismatch expected=' + expected + ' paid=' + paid,
      amount_minor_paid: paid,
      paid_utc: _iso(new Date()),
      raw: _mergeRaw_(pay.raw, { verify: v.raw || {} })
    });
    return _json({ ok:false, error:'amount_mismatch' });
  }

  // 3) Mark as PAID
  _paymentsPatch_(reference, {
    status:'PAID',
    amount_minor_paid: paid,
    paid_utc: _iso(new Date()),
    raw: _mergeRaw_(pay.raw, { verify: v.raw || {} })
  });

  // IMPORTANT: reload latest row after patch (ensures we see any new fields)
  pay = _paymentsGetByReference_(reference) || pay;

  // 4) Activate access in PortalAuthv2
  var act = _portalActivate_(pay);
  if(act && act.ok){
    // 5) Mark as ACTIVATED
    _paymentsPatch_(reference, {
      status:'ACTIVATED',
      activated_utc: _iso(new Date()),
      portal_subscription_id: act.subscription_id || '',
      user_id: act.user_id || String(pay.user_id || '').trim(), // ✅ ADD
      raw: _mergeRaw_(pay.raw, { activation: act.raw || {} })
    });

    return _json({
      ok:true,
      reference: reference,
      status:'ACTIVATED',
      portal_subscription_id: act.subscription_id || ''
    });
  }

  var ae = String((act && act.error) || '').toLowerCase();

  // PAY-FIRST: user not found => setup required (do NOT mark FAILED)
  if(ae.indexOf('user_not_found') !== -1){
    var setupTok2 = String(pay.setup_token || '').trim() || _randToken_();
    _paymentsPatch_(reference, {
      status:'SETUP_REQUIRED',
      setup_token: setupTok2,
      raw: _mergeRaw_(pay.raw, { activation: act.raw || {}, setup_required:true, reason:'user_not_found_after_paid' })
    });

    return _json({
      ok:true,
      reference: reference,
      status:'SETUP_REQUIRED',
      email: String(pay.email || '').trim().toLowerCase(),
      product_id: String(pay.product_id || '').trim().toUpperCase(),
      product_name: String(pay.product_name || '').trim(),
      amount_minor_expected: pay.amount_minor_expected || '',
      currency: pay.currency || '',
      setup_token: setupTok2,
      phone_number: String(pay.phone_number || '').trim(),
  program_id: String(pay.program_id || '').trim().toUpperCase(),
  cohort: String(pay.cohort || '').trim(),
  username: String(pay.username || '').trim().toLowerCase()
    });
  }

  // Any other activation failure => real failure
  _paymentsPatch_(reference, {
    status:'FAILED',
    failure_note:'activation_failed: ' + ((act && act.error) || ''),
    raw: _mergeRaw_(pay.raw, { activation: act.raw || {} })
  });

  return _json({ ok:false, error:'activation_failed', detail: (act && act.error) || '' });
}

/** ============================================================
 * API: setup_complete (PAY-FIRST)
 * - Inputs: reference, forename, surname, password, (optional) phone_number, program_id, setup_token
 * - Requires payment status to be PAID or SETUP_REQUIRED
 * - Creates user via PortalAuthv2 self_register_paid (idempotent: handles email_exists)
 * - Calls payments_activate to activate access
 * - Marks payment row ACTIVATED on success
 * ============================================================ */
function apiSetupComplete(args){
  const reference    = String(args.reference || '').trim();
  const forename     = String(args.forename  || '').trim();
  const surname      = String(args.surname   || '').trim();
  const password     = String(args.password  || '');
  const phone_number = String(args.phone_number || '').trim();
  const program_id   = String(args.program_id || '').trim();

  // ✅ NEW
  const cohort       = String(args.cohort || '').trim();
  const username     = String(args.username || '').trim().toLowerCase();

  const setup_token  = String(args.setup_token || '').trim();

  // Optional client info
  const ua = String(args.ua || '');
  const ip = String(args.ip || '');

  if(!reference) return _json({ ok:false, error:'missing_reference' });

  const pay = _paymentsGetByReference_(reference);
  if(!pay) return _json({ ok:false, error:'payment_not_found' });

  const st = String(pay.status || '').trim().toUpperCase();

  // Idempotent
  if(st === 'ACTIVATED'){
    return _json({
      ok:true,
      status:'ACTIVATED',
      reference: reference,
      portal_subscription_id: pay.portal_subscription_id || ''
    });
  }

  if(st === 'FAILED'){
    return _json({ ok:false, error:'payment_failed', detail: pay.failure_note || '' });
  }

  if(st !== 'PAID' && st !== 'SETUP_REQUIRED'){
    return _json({ ok:false, error:'not_ready_for_setup', status: st });
  }

  // Source-of-truth values come from the payment row
  const email      = String(pay.email || '').trim().toLowerCase();
  const product_id = String(pay.product_id || '').trim().toUpperCase();

  if(!email)      return _json({ ok:false, error:'missing_email_on_payment' });
  if(!product_id) return _json({ ok:false, error:'missing_product_id_on_payment' });

  // Basic form validation
  if(!forename || !surname || !password){
    return _json({ ok:false, error:'missing_fields' });
  }

  // If frontend omitted optional fields, fallback to payment-row values where possible
  const program_id2   = program_id || String(pay.program_id || '').trim();
  const phone_number2 = phone_number || String(pay.phone_number || '').trim();

  // Optional token check (only enforce if column exists & has value)
  const storedTok = String(pay.setup_token || '').trim();
  if(storedTok){
    if(!setup_token) return _json({ ok:false, error:'missing_setup_token' });
    if(setup_token !== storedTok) return _json({ ok:false, error:'setup_token_mismatch' });
  } else {
    if(setup_token){
      _paymentsPatch_(reference, { setup_token: setup_token });
    }
  }

  // 1) Create user (paid onboarding) — idempotent
  let reg = _portalPost_({
    action: 'self_register_paid',
    forename, surname,
    email,
    password,
    phone_number: phone_number2,
    program_id: program_id2,

    // ✅ NEW (mirrors old flow)
    cohort: cohort,
    username: username,

    // helpful audit fields
    product_id,
    ua, ip
  });

  let new_user_id = '';
  if(reg && reg.ok){
    new_user_id = String(reg.user_id || '').trim();
  } else {
    const peRaw = String((reg && reg.error) || '');
    const pe = peRaw.toLowerCase();

    const isEmailExists =
      pe.indexOf('email_exists') !== -1 ||
      pe.indexOf('user_exists') !== -1 ||
      pe.indexOf('already_exists') !== -1;

    if(!isEmailExists){
      _paymentsPatch_(reference, {
        raw: _mergeRaw_(pay.raw, { setup_complete: { ok:false, step:'register', portal: reg || {} } })
      });
      // ✅ Important: return portal_error so the confirmation page can react (username_exists, invalid_username, etc.)
      return _json({
        ok:false,
        error:'portal_register_failed',
        portal_error: (reg && reg.error) || '',
        raw: reg || {}
      });
    }
  }

  // 2) Patch payment row with any info we now have (safe if cols absent)
  _paymentsPatch_(reference, {
    user_id: new_user_id || String(pay.user_id || '').trim(),
    phone_number: phone_number2,
    program_id: program_id2,

    // ✅ NEW (safe if columns exist)
    cohort: cohort,
    username: username,

    setup_completed_utc: _iso(new Date()),
    raw: _mergeRaw_(pay.raw, {
      setup_complete: {
        ok:true,
        email: email,
        user_id: new_user_id || '',
        program_id: (program_id2 || ''),
        phone_number: (phone_number2 || ''),
        cohort: (cohort || ''),
        username: (username || '')
      }
    })
  });

  // Reload updated row
  const pay2 = _paymentsGetByReference_(reference) || pay;

  // 3) Activate access
  const act = _portalActivate_(pay2);

  if(act && act.ok){
    _paymentsPatch_(reference, {
      status: 'ACTIVATED',
      activated_utc: _iso(new Date()),
      portal_subscription_id: act.subscription_id || '',
      user_id: act.user_id || String(pay2.user_id || '').trim(),
      raw: _mergeRaw_(pay2.raw, { activation_after_setup: act.raw || {} })
    });

    return _json({
      ok:true,
      status:'ACTIVATED',
      reference: reference,
      portal_subscription_id: act.subscription_id || ''
    });
  }

  const detail = String((act && act.error) || '').trim() || 'activation_failed';
  _paymentsPatch_(reference, {
    status: (st === 'SETUP_REQUIRED') ? 'SETUP_REQUIRED' : 'PAID',
    failure_note: 'activation_failed_after_setup: ' + detail,
    raw: _mergeRaw_(pay2.raw, { activation_after_setup: act.raw || {}, activation_failed:true })
  });

  return _json({ ok:false, error:'activation_failed', detail: detail });
}


