/** ========== PORTAL HELPERS ========== */

// Calls PortalAuthv2 WebApp (POST form-encoded)
function _portalPost_(payload){
  const url = PORTAL_AUTH_URL;
  const resp = UrlFetchApp.fetch(url, {
    method: 'post',
    contentType: 'application/x-www-form-urlencoded',
    payload: payload,
    muteHttpExceptions: true
  });
  const txt = resp.getContentText() || '';
  try { return JSON.parse(txt); } catch(_){ return { ok:false, error:'bad_portal_json', raw:txt }; }
}

// NEW: Verify token via PortalAuthv2 doGet?action=verify&token=...
function _portalVerifyToken_(token){
  try{
    const url = PORTAL_AUTH_URL + '?action=verify&token=' + encodeURIComponent(String(token||'').trim());
    const resp = UrlFetchApp.fetch(url, { method:'get', muteHttpExceptions:true });
    const txt = resp.getContentText() || '';
    const j = JSON.parse(txt);

    // Expect j.ok true. Payload shape may vary; we return raw as-is.
    if(!j || !j.ok) return { ok:false, raw:j };
    return j;
  } catch(e){
    return { ok:false, error:'verify_fetch_failed:' + String(e) };
  }
}

// Activation bridge
function _portalActivate_(payRow){
  const product_id = String(payRow.product_id || '').trim().toUpperCase();
  const email      = String(payRow.email || '').trim().toLowerCase();
  const user_id    = String(payRow.user_id || '').trim();
  const reference  = String(payRow.reference || '').trim();

  if(ACTIVATION_MODE === 'PAYMENTS_ACTIVATE'){
    const secret = _getProp_(PROP_PORTAL_PAYMENTS_SECRET);
    if(!secret) return { ok:false, error:'missing_portal_payments_secret' };

    const res = _portalPost_({
      action: 'payments_activate',
      secret: secret,
      user_id: user_id,
      email: email,
      product_id: product_id,
      source: 'PAYSTACK',
      source_ref: reference
    });

return {
  ok: !!res.ok,
  subscription_id: res.subscription_id || '',
  user_id: res.user_id || '',   // ✅ if PortalAuth returns it
  error: res.error || '',
  raw: res
};

  }

  // Fallback (NOT recommended): uses admin token to call existing assign_product
  const adminToken = _getProp_(PROP_PORTAL_ADMIN_TOKEN);
  if(!adminToken) return { ok:false, error:'missing_portal_admin_token' };

  const res2 = _portalPost_({
    action: 'assign_product',
    token: adminToken,
    user_id: user_id,
    email: email,
    product_id: product_id
  });

  if(res2 && res2.ok) return { ok:true, subscription_id: res2.subscription_id || '', raw: res2 };
  if(res2 && String(res2.error||'') === 'subscription_exists'){
    return { ok:true, subscription_id:'', raw: res2 };
  }

  return { ok:false, error: res2.error || 'assign_product_failed', raw: res2 };
}

// Read product price dynamically from PortalAuthv2 products tab
function _getProductPricingFromPortal_(product_id){
  try{
    const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
    const sh = ss.getSheetByName(PORTAL_TAB_PRODUCTS);
    if(!sh) return { ok:false, error:'portal_products_tab_missing' };

    const values = sh.getDataRange().getValues();
    if(values.length < 2) return { ok:false, error:'portal_products_empty' };

    const headers = values[0].map(String);
    const idx = {};
    headers.forEach((h,i)=> idx[String(h).trim()] = i);

    const pidCol = idx['product_id'];
    if(pidCol === undefined) return { ok:false, error:'portal_products_missing_product_id_col' };

    let row = null;
    for(let r=1;r<values.length;r++){
      const pid = String(values[r][pidCol] || '').trim().toUpperCase();
      if(pid === product_id){ row = values[r]; break; }
    }
    if(!row) return { ok:false, error:'product_not_found' };

    const price_minor = parseInt(row[idx['price_minor']], 10);
    const currency = String(row[idx['currency']] || 'GHS').trim().toUpperCase();
    const name = String(row[idx['name']] || '').trim();

    if(!price_minor || price_minor <= 0) return { ok:false, error:'product_price_invalid' };

    return { ok:true, product_id, price_minor, currency, name };
  } catch(e){
    return { ok:false, error:'portal_product_lookup_error: ' + String(e) };
  }
}


/** ========== PAYSTACK HELPERS ========== */

function _paystackInitialize_({ email, amount_minor, currency, metadata, callback_url }){
  const secret = _getProp_(PROP_PAYSTACK_SECRET_KEY);
  if(!secret) return { ok:false, error:'missing_paystack_secret_key' };

  const payload = {
    email: email,
    amount: amount_minor,
    currency: currency || 'GHS',
    metadata: metadata || {}
  };

  if (callback_url) payload.callback_url = callback_url;

  const resp = UrlFetchApp.fetch(PAYSTACK_INIT_URL, {
    method: 'post',
    contentType: 'application/json',
    headers: { Authorization: 'Bearer ' + secret },
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  });

  const txt = resp.getContentText() || '';
  let obj = {};
  try { obj = JSON.parse(txt); } catch(_){ obj = {}; }

  if(!obj || obj.status !== true || !obj.data){
    return { ok:false, error:(obj && obj.message) ? obj.message : 'init_failed', raw: obj };
  }

  return {
    ok:true,
    authorization_url: obj.data.authorization_url,
    access_code: obj.data.access_code,
    reference: obj.data.reference,
    raw: obj
  };
}

function _paystackVerify_(reference){
  const secret = _getProp_(PROP_PAYSTACK_SECRET_KEY);
  if(!secret) return { ok:false, error:'missing_paystack_secret_key' };

  const resp = UrlFetchApp.fetch(PAYSTACK_VERIFY_URL + encodeURIComponent(reference), {
    method: 'get',
    headers: { Authorization: 'Bearer ' + secret },
    muteHttpExceptions: true
  });

  const txt = resp.getContentText() || '';
  let obj = {};
  try { obj = JSON.parse(txt); } catch(_){ obj = {}; }

  if(!obj || obj.status !== true || !obj.data){
    return { ok:false, error:(obj && obj.message) ? obj.message : 'verify_failed', raw: obj };
  }

  const st = String(obj.data.status || '').toLowerCase();
  if(st !== 'success'){
    return { ok:false, error:'not_success_status:' + st, raw: obj };
  }

  const amount_minor_paid = parseInt(obj.data.amount, 10);
  return { ok:true, amount_minor_paid, raw: obj };
}


/** ========== PAYMENTS SHEET HELPERS ========== */

function _paymentsSheet_(){
  // Payments tab lives in PAYMENTS_DB_ID if provided, otherwise fallback to PORTAL_DB_ID
  const dbId = (PAYMENTS_DB_ID && String(PAYMENTS_DB_ID).trim()) ? String(PAYMENTS_DB_ID).trim() : PORTAL_DB_ID;
  const ss = SpreadsheetApp.openById(dbId);
  const sh = ss.getSheetByName(TAB_PAYMENTS);
  if(!sh) throw new Error('missing_tab_' + TAB_PAYMENTS + '_in_' + dbId);
  return sh;
}

function _headers_(sh){
  const vals = sh.getRange(1,1,1,sh.getLastColumn()).getValues()[0];
  return vals.map(String);
}

function _rowToObj_(headers, row){
  const o = {};
  headers.forEach((h,i)=> o[h] = row[i]);
  return o;
}

function _findRowIndexBy_(sh, colName, value){
  const headers = _headers_(sh);
  const col = headers.indexOf(colName);
  if(col < 0) return -1;

  const last = sh.getLastRow();
  if(last < 2) return -1;

  const rng = sh.getRange(2, col+1, last-1, 1).getValues();
  const target = String(value || '').trim();
  for(let i=0;i<rng.length;i++){
    if(String(rng[i][0] || '').trim() === target){
      return i + 2;
    }
  }
  return -1;
}

function _appendObj_(sh, headers, obj){
  const row = headers.map(h => (obj[h] !== undefined ? obj[h] : ''));
  sh.appendRow(row);
}

function _updateObj_(sh, headers, rowIndex, obj){
  const row = headers.map(h => (obj[h] !== undefined ? obj[h] : ''));
  sh.getRange(rowIndex, 1, 1, headers.length).setValues([row]);
}

function _paymentsGetByReference_(reference){
  const sh = _paymentsSheet_();
  const headers = _headers_(sh);
  const idx = _findRowIndexBy_(sh, 'reference', reference);
  if(idx < 0) return null;
  const row = sh.getRange(idx,1,1,headers.length).getValues()[0];
  return _rowToObj_(headers, row);
}

function _paymentsUpsertByReference_(reference, obj){
  const sh = _paymentsSheet_();
  const headers = _headers_(sh);
  const idx = _findRowIndexBy_(sh, 'reference', reference);

  if(idx < 0){
    _appendObj_(sh, headers, obj);
    return;
  }
  const row = sh.getRange(idx,1,1,headers.length).getValues()[0];
  const cur = _rowToObj_(headers, row);
  const merged = Object.assign({}, cur, obj);
  _updateObj_(sh, headers, idx, merged);
}

function _paymentsPatch_(reference, patch){
  const sh = _paymentsSheet_();
  const headers = _headers_(sh);
  const idx = _findRowIndexBy_(sh, 'reference', reference);
  if(idx < 0) return;

  const row = sh.getRange(idx,1,1,headers.length).getValues()[0];
  const cur = _rowToObj_(headers, row);
  const merged = Object.assign({}, cur, patch);
  _updateObj_(sh, headers, idx, merged);
}

function _mergeRaw_(rawStr, addObj){
  let base = {};
  try { base = rawStr ? JSON.parse(String(rawStr)) : {}; } catch(_){ base = {}; }
  const merged = Object.assign({}, base, addObj || {});
  return JSON.stringify(merged);
}


