function apiMeta(){
  const cache = CacheService.getScriptCache();
  const hit = cache.get('qa_meta_v1');
  if(hit){
    try { return _json(JSON.parse(hit)); } catch(_){}
  }

  const programs = _getProgramsFromPortal_();
