  }

  const out = {
    ok: true,
    programs: programs.programs || [],
    products: products.products || []
  };

  cache.put('qa_meta_v1', JSON.stringify(out), 300);
  return _json(out);
}

// Programs: prefer "programs" tab; fallback to distinct program_id from program_course_map
function _getProgramsFromPortal_(){
  try{
    const ss = SpreadsheetApp.openById(PORTAL_DB_ID);

    let sh = ss.getSheetByName(PORTAL_TAB_PROGRAMS);
    if(sh){
      const v = sh.getDataRange().getValues();
      if(v.length < 2) return { ok:true, programs: [] };

      const headers = v[0].map(x=>String(x).trim());
      const idx = {};
      headers.forEach((h,i)=>idx[h]=i);

      const pidCol = idx['program_id'];
      if(pidCol === undefined) return { ok:false, programs:[], error:'programs_missing_program_id' };

      const pnameCol = (idx['program_name'] !== undefined) ? idx['program_name'] : idx['name'];

      const seen = {};
      const out = [];
      for(let r=1;r<v.length;r++){
        const program_id = String(v[r][pidCol]||'').trim().toUpperCase();
        if(!program_id || seen[program_id]) continue;
        seen[program_id]=true;

        const program_name = (pnameCol!==undefined) ? String(v[r][pnameCol]||'').trim() : '';
        out.push({ program_id, program_name: program_name || program_id });
      }

      out.sort((a,b)=>a.program_name.localeCompare(b.program_name));
      return { ok:true, programs: out };
    }

    sh = ss.getSheetByName('program_course_map');
    if(!sh) return { ok:true, programs: [] };

    const v2 = sh.getDataRange().getValues();
    if(v2.length < 2) return { ok:true, programs: [] };

    const headers2 = v2[0].map(x=>String(x).trim());
    const pidCol2 = headers2.indexOf('program_id');
    if(pidCol2 < 0) return { ok:false, programs:[], error:'pcmap_missing_program_id' };

    const seen2 = {};
    const out2 = [];
    for(let r=1;r<v2.length;r++){
      const program_id = String(v2[r][pidCol2]||'').trim().toUpperCase();
      if(!program_id || seen2[program_id]) continue;
      seen2[program_id]=true;
      out2.push({ program_id, program_name: program_id });
    }
    out2.sort((a,b)=>a.program_name.localeCompare(b.program_name));
    return { ok:true, programs: out2 };
  } catch(e){
    return { ok:false, programs:[], error:'programs_lookup_error:' + String(e) };
  }
}

// Products: return ACTIVE, non-TRIAL only, with price fields (safe public subset)
function _getPublicProductsFromPortal_(){
  try{
    const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
    const sh = ss.getSheetByName(PORTAL_TAB_PRODUCTS);
    if(!sh) return { ok:false, products:[], error:'portal_products_tab_missing' };

    const v = sh.getDataRange().getValues();
    if(v.length < 2) return { ok:true, products: [] };

    const headersRaw = v[0].map(x => String(x||'').trim());
    const headers = headersRaw.map(h => h.toLowerCase().replace(/\s+/g,'_'));
    const idx = {};
    headers.forEach((h,i)=> idx[h]=i);

    const pidCol    = idx['product_id'] ?? idx['id'];
    const nameCol   = idx['name'] ?? idx['product_name'] ?? idx['plan_name'];
    const priceCol  = idx['price_minor'] ?? idx['amount_minor'] ?? idx['price'];
    const curCol    = idx['currency'] ?? idx['curr'];
    const statusCol = idx['status'];
    const kindCol   = idx['kind'] ?? idx['type'];

    if(pidCol === undefined || nameCol === undefined || priceCol === undefined){
      return { ok:false, products:[], error:'products_missing_required_cols', debug_headers: headersRaw };
    }

    const out = [];
    for(let r=1;r<v.length;r++){
      const product_id = String(v[r][pidCol]||'').trim().toUpperCase();
      if(!product_id) continue;

      const status = (statusCol!==undefined) ? String(v[r][statusCol]||'').trim().toUpperCase() : 'ACTIVE';
      if(status && status !== 'ACTIVE') continue;

      const kind = (kindCol!==undefined) ? String(v[r][kindCol]||'').trim().toUpperCase() : '';
      if(kind === 'TRIAL') continue;

      const name = String(v[r][nameCol]||'').trim() || product_id;

      const rawPrice = v[r][priceCol];
      const price_minor = parseInt(String(rawPrice).replace(/,/g,'').trim(), 10);
      if(!price_minor || price_minor <= 0) continue;

      const currency = (curCol!==undefined) ? String(v[r][curCol]||'GHS').trim().toUpperCase() : 'GHS';

      out.push({ product_id, name, price_minor, currency });
    }

    out.sort((a,b)=>a.name.localeCompare(b.name));
    return { ok:true, products: out };
  } catch(e){
    return { ok:false, products:[], error:'products_lookup_error:' + String(e) };
  }
}


/** ========== UTIL ========== */

function _json(obj){
  return ContentService
    .createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);
}

function _iso(d){ return Utilities.formatDate(d, 'Etc/UTC', "yyyy-MM-dd'T'HH:mm:ss'Z'"); }

function _merge(a,b){
  const o = {};
  Object.keys(a||{}).forEach(k=> o[k]=a[k]);
  Object.keys(b||{}).forEach(k=> o[k]=b[k]);
  return o;
}

function _randToken_(){
  // short, URL-safe token
  var seed = Utilities.getUuid() + '|' + new Date().getTime() + '|' + Math.random();
  var bytes = Utilities.computeDigest(Utilities.DigestAlgorithm.SHA_256, seed);
  return Utilities.base64EncodeWebSafe(bytes).replace(/=+$/,'').slice(0, 32);
}

function _addQueryParam_(url, key, value){
  if(!url) return '';
  var u = String(url);
  var sep = (u.indexOf('?') === -1) ? '?' : '&';
  return u + sep + encodeURIComponent(key) + '=' + encodeURIComponent(String(value || ''));
}


function _getProp_(k){
  return PropertiesService.getScriptProperties().getProperty(k) || '';
}

function _getHeaderCI_(e, name){
  const want = String(name || '').toLowerCase();
  const h = (e && e.headers) ? e.headers : null;
  if(!h) return '';
  for (var k in h){
    if (String(k).toLowerCase() === want) return h[k];
  }
  return '';
}


function _hmacSha512Hex_(message, secret){
  const sigBytes = Utilities.computeHmacSha512Signature(message, secret);
  return sigBytes.map(b => ('0' + (b & 0xFF).toString(16)).slice(-2)).join('');
}

/**
 * Generate a strong shared secret for PORTAL_PAYMENTS_SECRET.
 * Run once, then copy the output from Logs.
 */
function qaGeneratePortalPaymentsSecret() {
  var seed = [
    Utilities.getUuid(), Utilities.getUuid(), Utilities.getUuid(),
    String(new Date().getTime()),
    String(Math.random()), String(Math.random())
  ].join('|');

  var bytes = Utilities.computeDigest(Utilities.DigestAlgorithm.SHA_256, seed);
  var secret = Utilities.base64EncodeWebSafe(bytes).replace(/=+$/,'');

  Logger.log('PORTAL_PAYMENTS_SECRET = ' + secret);
  return secret;
}
